function deviantARTGalleryPlugin(e, t, n) {
    var s = [];
    ! function () {
        console.log("fetching...");
        var a = "http://backend.deviantart.com/rss.xml?q=gallery:" + e + "/" + t;
        window.callback = function (e) {
            for (var t = e.items, a = 0, i = t.length; a < i; a++) {
                var l = {};
                l.title = t[a].title, l.image = t[a].enclosure.link, s.push(l)
            }
            for (var d = "", a = 0, i = s.length; a < i; a++) d += '<img aos-data="zoom-in" class="imgs cards imgcard daImgs" src="' + s[a].image + '"/>';
            document.getElementById("daImg").innerHTML = d, console.log("images fetched.\n\nDeviant Art Gallery Plugin by jamesl1001\nhttps://github.com/jamesl1001/deviantART-Gallery-Plugin")
            const event = new Event('finish');
            document.getElementById('daImg').dispatchEvent(event);
        };
        var i = document.createElement("script");
        i.src = "https://api.rss2json.com/v1/api.json?callback=callback&rss_url=" + escape(a), document.body.appendChild(i)
    }()
}